set-variable.value:
@{
            try {
                var qsDeployment = context.Request.Url.Query.GetValueOrDefault("deployment", null);
                if (!string.IsNullOrEmpty(qsDeployment)) return qsDeployment;
                var body = context.Request.Body.As<JObject>(preserveContent: true);
                if (body != null && body["deployment"] != null) return body["deployment"].ToString();
            } catch {}
            return "unknown";
        }
